      tags: ['security', 'cryptomining', 'resource-hijacking', 'compromised-instance', 'vpc-flow'],
      requiredFields: ['srcaddr', 'dstaddr', 'dstport', 'action', 'protocol', 'bytes', 'packets', 'instance_id', 'vpc_id', 'start', 'end'],
      detectionLogic: 'Alert on any outbound connection (ACCEPT) from internal IPs to known Stratum mining ports (3333, 4444, 5555, 14433, 14444). Any single connection to these ports is high-confidence malicious. Also detect sustained long-duration flows (>30 minutes) to these ports indicating active mining sessions.',
      falsePositives: ['Security research or honeypot infrastructure intentionally connecting to mining pools', 'Development/test environments testing blockchain applications'],
      tuningGuidance: 'This detection has very few false positives — mining ports are rarely used for legitimate purposes. Whitelist only verified research/blockchain development instances. Consider expanding port list based on emerging mining protocols.',
      investigationWorkflow: '1. Immediately identify the instance and isolate it from the network\n2. Determine when the mining connection first appeared\n3. Check CloudTrail for how the instance was compromised (key exposure, SSRF, vulnerable service)\n4. Review instance metadata for unauthorized software installations\n5. Check for other indicators of compromise on the same instance\n6. Assess blast radius — are other instances in the same subnet affected?',
      criblSearchQueries: [
        {
          name: 'Active mining connections',
          description: 'Find any connections to known mining pool ports',
          query: 'dataset="$DATASET" action="ACCEPT" dstport in (3333, 4444, 5555, 14433, 14444) earliest=-7d\n| where srcaddr matches regex "^(10\\.|172\\.(1[6-9]|2[0-9]|3[01])\\.|192\\.168\\.)"\n| summarize FlowCount=count(), TotalBytes=sum(bytes), FirstSeen=min(start), LastSeen=max(end) by srcaddr, dstaddr, dstport, instance_id\n| order by LastSeen desc'
        },
        {
          name: 'Mining session duration analysis',
          description: 'Identify long-duration mining sessions indicating active mining',
          query: 'dataset="$DATASET" action="ACCEPT" dstport in (3333, 4444, 5555, 14433, 14444) earliest=-7d\n| where srcaddr matches regex "^(10\\.|172\\.(1[6-9]|2[0-9]|3[01])\\.|192\\.168\\.)"\n| extend duration_seconds=(end-start)\n| where duration_seconds > 1800\n| summarize AvgDuration=avg(duration_seconds), MaxDuration=max(duration_seconds), SessionCount=count() by srcaddr, dstaddr, instance_id\n| order by MaxDuration desc'
        },
        {
          name: 'Mining activity timeline',
          description: 'Trend mining connections over time to identify when compromise began',
          query: 'dataset="$DATASET" action="ACCEPT" dstport in (3333, 4444, 5555, 14433, 14444) earliest=-7d\n| where srcaddr matches regex "^(10\\.|172\\.(1[6-9]|2[0-9]|3[01])\\.|192\\.168\\.)"\n| timestats span=1h count() by srcaddr, dstport'
        },
        {
          name: 'All outbound activity from mining-suspect instance',
          description: 'Full network profile of the suspected compromised instance',
          query: 'dataset="$DATASET" action="ACCEPT" srcaddr="$SOURCE_IP" earliest=-24h\n| where not(dstaddr matches regex "^(10\\.|172\\.(1[6-9]|2[0-9]|3[01])\\.|192\\.168\\.)")\n| summarize TotalBytes=sum(bytes), FlowCount=count() by dstaddr, dstport\n| order by TotalBytes desc\n| limit 50'
        }
      ]
