  {
    id: 'sec-f5-002',
    name: 'DDoS / Connection Flood',
    objective: 'Detect distributed denial-of-service attacks and connection floods by identifying connection counts approaching configured limits or single sources generating excessive concurrent connections.',
    severity: 'Critical',
    mitre: ['T1498 - Network Denial of Service', 'T1499 - Endpoint Denial of Service'],
    tags: ['security', 'ddos', 'dos', 'availability', 'connection-flood'],
    requiredFields: ['timestamp', 'virtual_server', 'client_ip', 'connection_count', 'connection_limit', 'pool_name', 'pool_member_status', 'response_time_ms', 'server_latency_ms'],
    detectionLogic: 'Alert when connection_count exceeds 80% of connection_limit for any virtual server. Additionally detect single client_ip generating connections exceeding 2 standard deviations above the mean. Monitor for correlation with rising response_time_ms indicating resource exhaustion.',
    falsePositives: ['Legitimate traffic spikes during product launches or marketing events', 'Load testing activities from authorized sources', 'Misconfigured connection limits that are set too low for normal traffic'],
    tuningGuidance: 'Adjust connection_limit threshold percentage based on virtual server capacity. Whitelist load test source IPs. Set different thresholds for internet-facing vs internal virtual servers. Consider time-of-day baselines for cyclical traffic patterns.',
    investigationWorkflow: '1. Check current connection_count vs connection_limit ratio across virtual servers\n2. Identify top client_ips by connection volume in the alert window\n3. Determine if traffic is distributed (DDoS) or single-source (DoS)\n4. Check pool_member_status — are backend servers going unhealthy under load?\n5. Review response_time_ms trends — is latency degrading for legitimate users?\n6. Correlate with geo_country to identify geographic concentration of attack sources',
    criblSearchQueries: [
      {
        name: 'Connection utilization by virtual server',
        description: 'Find virtual servers approaching their connection limits',
        query: 'dataset="$DATASET" earliest=-1h\n| extend utilization=round(connection_count * 100.0 / connection_limit, 1)\n| where utilization > 70\n| summarize MaxUtil=max(utilization), AvgUtil=avg(utilization), MaxConns=max(connection_count) by virtual_server, connection_limit\n| order by MaxUtil desc'
      },
      {
        name: 'Top connection generators by client IP',
        description: 'Identify individual clients generating the most connections',
        query: 'dataset="$DATASET" earliest=-1h\n| summarize TotalConnections=count(), UniqueVServers=dcount(virtual_server) by client_ip\n| where TotalConnections > 500\n| order by TotalConnections desc\n| limit 25'
      },
      {
        name: 'Connection flood trend',
        description: 'Visualize connection count over time to identify flood onset',
        query: 'dataset="$DATASET" earliest=-4h\n| timestats span=1m max(connection_count) by virtual_server'
      },
      {
        name: 'Response time degradation during flood',
        description: 'Correlate rising connection counts with response time impact',
        query: 'dataset="$DATASET" earliest=-1h\n| summarize AvgResponse=avg(response_time_ms), P95Response=max(response_time_ms), Connections=count() by virtual_server\n| where P95Response > 5000\n| order by P95Response desc'
      }
    ]
  },
  {
    id: 'sec-f5-003',
    name: 'Bot / Scanner Detection',
    objective: 'Identify automated bots and vulnerability scanners probing the application by detecting suspicious user-agent strings, rapid sequential requests to discovery paths, and response timing anomalies.',
    severity: 'Medium',
    mitre: ['T1595 - Active Scanning', 'T1592 - Gather Victim Host Information', 'T1018 - Remote System Discovery'],
    tags: ['security', 'reconnaissance', 'bot', 'scanner', 'enumeration'],
    requiredFields: ['timestamp', 'client_ip', 'http_method', 'http_uri', 'http_status', 'user_agent', 'response_time_ms', 'virtual_server', 'bytes_out'],
    detectionLogic: 'Alert when user_agent matches known scanner signatures (sqlmap, nikto, nmap, dirbuster, gobuster, etc.) or is empty/abnormal. Detect rapid sequential requests (>50 unique URIs per minute from single client_ip) targeting discovery paths (/admin, /.env, /wp-login, /api/swagger). Flag response patterns with high 404/403 ratios indicating enumeration.',
    falsePositives: ['Authorized vulnerability scanners (Qualys, Nessus, Rapid7)', 'SEO crawlers with uncommon user-agent strings', 'Health monitoring systems with minimal user-agent headers'],
    tuningGuidance: 'Maintain allowlist of authorized scanner IPs. Tune unique URI threshold based on application complexity. Exclude known bot user-agents that are benign (Googlebot, etc.). Adjust 404 ratio threshold per application.',
    investigationWorkflow: '1. Examine the user_agent string — does it match known scanning tools?\n2. Review the pattern of http_uri requests — sequential enumeration or targeted?\n3. Calculate the 404/403 response ratio for the client_ip\n4. Check request rate (requests per second) for the client_ip\n5. Determine if the source IP has been seen before or is a new actor\n6. Review if any requests received 200 responses indicating discovered resources',
    criblSearchQueries: [
      {
        name: 'Known scanner user-agents',
        description: 'Detect requests from tools commonly used for vulnerability scanning',
        query: 'dataset="$DATASET" earliest=-24h\n| where user_agent contains "sqlmap" or user_agent contains "nikto" or user_agent contains "nmap" or user_agent contains "dirbuster" or user_agent contains "gobuster" or user_agent contains "masscan" or user_agent == ""\n| summarize Requests=count(), UniqueURIs=dcount(http_uri) by client_ip, user_agent\n| order by Requests desc'
      },
      {
        name: 'High 404 ratio by source (enumeration behavior)',
        description: 'Find clients receiving mostly 404/403 responses indicating path enumeration',
        query: 'dataset="$DATASET" earliest=-1h\n| summarize Total=count(), NotFound=countif(http_status == 404), Forbidden=countif(http_status == 403) by client_ip\n| extend ErrorRatio=round((NotFound + Forbidden) * 100.0 / Total, 1)\n| where ErrorRatio > 60 and Total > 20\n| order by Total desc'
      },
      {
        name: 'Rapid request rate per client',
        description: 'Identify clients making an unusually high number of requests per minute',
        query: 'dataset="$DATASET" earliest=-1h\n| summarize RequestCount=count(), UniqueURIs=dcount(http_uri), UniqueMethods=dcount(http_method) by client_ip\n| where RequestCount > 500 and UniqueURIs > 50\n| order by RequestCount desc\n| limit 20'
      },
      {
        name: 'Discovery path probing',
        description: 'Find requests targeting common admin and configuration discovery paths',
        query: 'dataset="$DATASET" earliest=-24h\n| where http_uri contains "/admin" or http_uri contains "/.env" or http_uri contains "/wp-login" or http_uri contains "/swagger" or http_uri contains "/.git" or http_uri contains "/phpinfo"\n| summarize Attempts=count() by client_ip, http_uri, http_status\n| order by Attempts desc'
      }
    ]
  },
  {
    id: 'sec-f5-004',
    name: 'SSL/TLS Downgrade Attack',
    objective: 'Detect clients attempting to negotiate deprecated or weak TLS protocols and cipher suites, which may indicate a downgrade attack or compromised client.',
    severity: 'High',
    mitre: ['T1557 - Adversary-in-the-Middle', 'T1040 - Network Sniffing', 'T1573 - Encrypted Channel'],
    tags: ['security', 'ssl', 'tls', 'encryption', 'downgrade', 'compliance'],
    requiredFields: ['timestamp', 'client_ip', 'virtual_server', 'ssl_protocol', 'ssl_cipher', 'ssl_handshake_failure', 'http_host', 'user_agent', 'geo_country'],
    detectionLogic: 'Alert when ssl_protocol is TLSv1.0 or TLSv1.1 (deprecated protocols). Flag connections using weak cipher suites (RC4, DES, 3DES, NULL, EXPORT ciphers). Detect ssl_handshake_failure spikes that may indicate protocol manipulation. Escalate when a single client_ip switches from strong to weak protocols across sessions.',
    falsePositives: ['Legacy systems or IoT devices that only support older TLS versions', 'Partner integrations using older libraries pending upgrade', 'Automated systems with outdated SSL stacks'],
    tuningGuidance: 'Maintain inventory of known legacy systems requiring TLS 1.0/1.1 and exclude from alerting. Set distinct severities for deprecated protocol use vs weak cipher negotiation. Consider alerting only on internet-facing virtual servers for compliance focus.',
    investigationWorkflow: '1. Identify the client_ip and determine if it is a known legacy system\n2. Check if the client normally connects with stronger protocols (downgrade indicator)\n3. Review ssl_cipher negotiated — is it cryptographically broken?\n4. Check for ssl_handshake_failure correlation suggesting protocol manipulation\n5. Examine user_agent — does the client claim to be a modern browser but negotiate old TLS?\n6. Assess geographic origin — correlate with geo_country for suspicious regions',
    criblSearchQueries: [
      {
        name: 'Deprecated TLS protocol usage',
        description: 'Find all connections using TLS 1.0 or TLS 1.1 — deprecated and vulnerable',
        query: 'dataset="$DATASET" earliest=-24h\n| where ssl_protocol in ("TLSv1", "TLSv1.0", "TLSv1.1")\n| summarize Connections=count(), UniqueClients=dcount(client_ip) by ssl_protocol, virtual_server\n| order by Connections desc'
      },
      {
        name: 'Weak cipher suite negotiation',
        description: 'Identify connections using cryptographically weak cipher suites',
        query: 'dataset="$DATASET" earliest=-24h\n| where ssl_cipher contains "RC4" or ssl_cipher contains "DES" or ssl_cipher contains "NULL" or ssl_cipher contains "EXPORT" or ssl_cipher contains "MD5"\n| summarize Connections=count() by client_ip, ssl_cipher, ssl_protocol, virtual_server\n| order by Connections desc'
      },
      {
        name: 'SSL handshake failures trend',
        description: 'Track handshake failures over time that may indicate protocol manipulation attempts',
        query: 'dataset="$DATASET" ssl_handshake_failure != "" earliest=-12h\n| timestats span=15m count() by virtual_server'
      },
      {
        name: 'Protocol downgrade detection per client',
        description: 'Find clients that have used both strong and weak protocols suggesting downgrade',
        query: 'dataset="$DATASET" earliest=-24h\n| summarize Protocols=dcount(ssl_protocol), Connections=count(), WeakCount=countif(ssl_protocol in ("TLSv1", "TLSv1.0", "TLSv1.1")) by client_ip\n| where Protocols > 1 and WeakCount > 0\n| order by WeakCount desc'
      }
    ]
  },
  {
    id: 'sec-f5-005',
    name: 'Credential Stuffing Attack',
    objective: 'Detect credential stuffing campaigns characterized by high-volume POST requests to authentication endpoints from multiple distributed sources with elevated authentication failure rates.',
    severity: 'High',
    mitre: ['T1110.004 - Credential Stuffing', 'T1078 - Valid Accounts', 'T1110 - Brute Force'],
    tags: ['security', 'authentication', 'credential-stuffing', 'brute-force', 'account-takeover'],
    requiredFields: ['timestamp', 'client_ip', 'x_forwarded_for', 'http_method', 'http_uri', 'http_status', 'virtual_server', 'response_time_ms', 'bytes_in', 'bytes_out', 'geo_country'],
    detectionLogic: 'Alert when POST requests to login/auth URIs exceed baseline thresholds. Detect distributed patterns: many unique client_ips (or x_forwarded_for) targeting the same authentication endpoint with >70% HTTP 401/403 response rates. Flag low bytes_out responses (failed auth) followed by occasional normal bytes_out (successful auth indicating compromised credential).',
    falsePositives: ['Legitimate users repeatedly failing password entry', 'SSO federation health checks sending POST to auth endpoints', 'Mobile apps with cached expired credentials re-authenticating'],
    tuningGuidance: 'Define authentication URIs specific to the application (e.g., /login, /oauth/token, /api/auth). Adjust failure ratio threshold based on normal user error rates. Consider x_forwarded_for for true source identification behind CDNs. Set minimum request volume to avoid alerting on individual user lockouts.',
    investigationWorkflow: '1. Identify the targeted authentication URI and virtual server\n2. Count unique source IPs — distributed sources indicate stuffing vs brute force\n3. Calculate the 401/403 to 200 ratio — high failure rate confirms credential testing\n4. Check for any successful (200) responses — these are potentially compromised accounts\n5. Review x_forwarded_for for true client IPs behind proxies/CDNs\n6. Correlate geo_country distribution — legitimate users cluster geographically, stuffing is dispersed',
    criblSearchQueries: [
      {
        name: 'Authentication failure volume by endpoint',
        description: 'Find login endpoints receiving high volumes of failed authentication attempts',
        query: 'dataset="$DATASET" http_method="POST" earliest=-4h\n| where http_uri contains "/login" or http_uri contains "/auth" or http_uri contains "/oauth" or http_uri contains "/signin"\n| summarize Total=count(), Failures=countif(http_status in (401, 403)), Successes=countif(http_status == 200), UniqueSources=dcount(client_ip) by http_uri, virtual_server\n| extend FailRate=round(Failures * 100.0 / Total, 1)\n| where Total > 50 and FailRate > 70\n| order by Failures desc'
      },
      {
        name: 'Distributed source analysis for auth endpoints',
        description: 'Identify credential stuffing by finding many unique IPs targeting the same login path',
        query: 'dataset="$DATASET" http_method="POST" http_status in (401, 403) earliest=-1h\n| where http_uri contains "/login" or http_uri contains "/auth"\n| summarize FailedAttempts=count() by client_ip, geo_country\n| order by FailedAttempts desc\n| limit 50'
      },
      {
        name: 'Successful logins during stuffing campaign',
        description: 'Find successful authentications during high-failure periods — potentially compromised accounts',
        query: 'dataset="$DATASET" http_method="POST" http_status=200 earliest=-4h\n| where http_uri contains "/login" or http_uri contains "/auth"\n| summarize Successes=count() by client_ip, x_forwarded_for, geo_country, virtual_server\n| order by Successes desc'
      },
      {
        name: 'Credential stuffing trend over time',
        description: 'Visualize authentication failure rate over time to identify campaign start and duration',
        query: 'dataset="$DATASET" http_method="POST" earliest=-12h\n| where http_uri contains "/login" or http_uri contains "/auth"\n| timestats span=5m count() by http_status'
      }
    ]
  },
  {
    id: 'sec-f5-006',
    name: 'Unauthorized Geographic Access',
    objective: 'Detect requests originating from geographic regions not approved for accessing sensitive virtual servers, which may indicate compromised credentials used from foreign locations or VPN/proxy abuse.',
    severity: 'Medium',
    mitre: ['T1078 - Valid Accounts', 'T1090 - Proxy', 'T1583 - Acquire Infrastructure'],
    tags: ['security', 'geofencing', 'access-control', 'compliance', 'impossible-travel'],
    requiredFields: ['timestamp', 'client_ip', 'geo_country', 'virtual_server', 'http_uri', 'http_host', 'http_status', 'ssl_client_cert_subject', 'user_agent'],
    detectionLogic: 'Alert when geo_country is not in the approved list for a given virtual_server hosting sensitive applications. Escalate when requests from unapproved geographies receive successful (200) responses. Detect impossible travel by identifying the same ssl_client_cert_subject or user session appearing from widely separated geo_country values within a short time window.',
    falsePositives: ['Employees traveling internationally for legitimate business', 'VPN exit nodes in unexpected countries', 'CDN or proxy services routing traffic through foreign POPs'],
    tuningGuidance: 'Define approved geo_country lists per virtual_server based on business requirements. Maintain an exception list for known VPN exit countries. Focus on sensitive applications only — public marketing sites need not be geo-fenced. Consider time-based thresholds for impossible travel (e.g., same identity from two countries within 30 minutes).',
    investigationWorkflow: '1. Identify the geo_country and client_ip generating the alert\n2. Determine if the virtual_server hosts sensitive or regulated data\n3. Check if the request was successful (200) or blocked (403)\n4. Review ssl_client_cert_subject if mutual TLS is configured — does the identity match known users?\n5. Look for the same client identity from approved geographies recently (impossible travel)\n6. Correlate with VPN logs or identity provider to determine if this is a legitimate remote user',
    criblSearchQueries: [
      {
        name: 'Requests from unapproved geographies',
        description: 'Find traffic from countries outside common approved regions targeting sensitive virtual servers',
        query: 'dataset="$DATASET" earliest=-24h\n| where not(geo_country in ("US", "CA", "GB", "DE", "AU"))\n| summarize Requests=count(), UniqueIPs=dcount(client_ip), SuccessCount=countif(http_status == 200) by geo_country, virtual_server\n| order by Requests desc'
      },
      {
        name: 'Geographic distribution per virtual server',
        description: 'Visualize which countries are accessing each virtual server to spot anomalies',
        query: 'dataset="$DATASET" earliest=-24h\n| summarize Requests=count(), UniqueClients=dcount(client_ip) by geo_country, virtual_server\n| order by Requests desc\n| limit 50'
      },
      {
        name: 'Successful access from unusual geographies',
        description: 'Focus on requests from unusual countries that received successful responses',
        query: 'dataset="$DATASET" http_status=200 earliest=-24h\n| where not(geo_country in ("US", "CA", "GB", "DE", "AU"))\n| summarize Requests=count() by client_ip, geo_country, virtual_server, http_uri\n| order by Requests desc'
      },
      {
        name: 'Geographic access trend over time',
        description: 'Track access from non-standard geographies over time to identify new campaigns',
        query: 'dataset="$DATASET" earliest=-7d\n| where not(geo_country in ("US", "CA", "GB", "DE", "AU"))\n| timestats span=1h count() by geo_country'
      }
    ]
  },
  {
    id: 'sec-f5-007',
    name: 'Backend Server Exploitation Indicators',
    objective: 'Detect signs that a backend server behind F5 has been compromised by identifying abnormal response patterns, unusual HTTP status codes, response time anomalies suggesting command execution, or unexpected response sizes indicating data exfiltration.',
    severity: 'High',
    mitre: ['T1190 - Exploit Public-Facing Application', 'T1505.003 - Web Shell', 'T1048 - Exfiltration Over Alternative Protocol'],
    tags: ['security', 'backend-compromise', 'web-shell', 'exfiltration', 'post-exploitation'],
    requiredFields: ['timestamp', 'server_ip', 'server_port', 'pool_name', 'http_status', 'http_uri', 'response_time_ms', 'server_latency_ms', 'bytes_out', 'client_ip', 'virtual_server', 'pool_member_status'],
    detectionLogic: 'Alert on anomalous backend behavior: (1) server_ip returning HTTP 500/502/503 spikes suggesting exploitation or instability, (2) response_time_ms anomalies — very fast responses to complex URIs (cached web shell) or very slow responses (command execution delay), (3) unusually large bytes_out relative to baseline for the same http_uri indicating data exfiltration, (4) single server_ip diverging from pool peer behavior patterns.',
    falsePositives: ['Application deployments causing temporary 500 errors', 'Legitimate large file downloads (reports, exports)', 'Database maintenance causing latency spikes on specific pool members'],
    tuningGuidance: 'Establish baseline response_time_ms and bytes_out per http_uri pattern. Compare individual server_ip behavior against pool peers. Exclude known large-response URIs (file downloads, report exports). Set minimum deviation threshold at 3x standard deviation from peer average.',
    investigationWorkflow: '1. Identify the server_ip exhibiting anomalous behavior and its pool membership\n2. Compare the server response patterns against other pool members for the same URIs\n3. Review http_status distribution — are 500 errors isolated to this server?\n4. Check response_time_ms — web shells often respond faster than normal application logic\n5. Analyze bytes_out anomalies — is data volume disproportionate to the request type?\n6. Correlate with the originating client_ip — was this server targeted by a prior attack (WAF violations)?',
    criblSearchQueries: [
      {
        name: 'Backend server error rate by pool member',
        description: 'Compare error rates across pool members to identify a potentially compromised server',
        query: 'dataset="$DATASET" earliest=-4h\n| summarize Total=count(), Errors=countif(http_status >= 500), AvgLatency=avg(server_latency_ms) by server_ip, pool_name\n| extend ErrorRate=round(Errors * 100.0 / Total, 1)\n| where ErrorRate > 5\n| order by ErrorRate desc'
      },
      {
        name: 'Response time anomalies per server',
        description: 'Find servers with response times deviating significantly from pool peers',
        query: 'dataset="$DATASET" earliest=-1h\n| summarize AvgResponse=avg(response_time_ms), P95Response=max(response_time_ms), MinResponse=min(response_time_ms), Requests=count() by server_ip, pool_name\n| where P95Response > 10000 or MinResponse < 5\n| order by P95Response desc'
      },
      {
        name: 'Unusual response size patterns',
        description: 'Detect servers sending abnormally large responses that may indicate data exfiltration',
        query: 'dataset="$DATASET" earliest=-4h\n| summarize AvgBytesOut=avg(bytes_out), MaxBytesOut=max(bytes_out), P95Bytes=max(bytes_out) by server_ip, http_uri\n| where P95Bytes > 1000000\n| order by P95Bytes desc\n| limit 25'
      },
      {
        name: 'Backend server health and exploitation correlation',
        description: 'Correlate pool member health issues with client IPs that may have exploited the server',
        query: 'dataset="$DATASET" http_status >= 500 earliest=-4h\n| summarize ErrorCount=count(), UniqueClients=dcount(client_ip), UniqueURIs=dcount(http_uri) by server_ip, pool_name, pool_member_status\n| where ErrorCount > 10\n| order by ErrorCount desc'
      }
    ]
  }
