      mitre: ['T1098 - Account Manipulation'],
      tags: ['security', 'identity', 'privilege-escalation', 'admin-role', 'change-management'],
      requiredFields: ['timestamp', 'actor_username', 'target_username', 'role_name', 'action', 'previous_roles', 'new_roles', 'source_ip', 'application_name'],
