          query: 'dataset="$DATASET" earliest=-24h\n| where request_uri contains "../" or request_uri contains "..%2f" or request_uri contains "%2e%2e" or request_uri contains "..\\\\"\n| summarize AttackCount=count(), StatusCodes=values(status_code), URIs=values(request_uri) by client_ip, vhost\n| order by AttackCount desc'
