          query: 'dataset="$DATASET" sc_status==404 earliest=-1h\n| summarize NotFoundCount=count(), UniquePaths=dcount(cs_uri_stem), Paths=values(cs_uri_stem) by c_ip, cs_host, cs_User_Agent\n| where NotFoundCount > 30 and UniquePaths > 20\n| order by NotFoundCount desc'
