          name: 'Suspicious domain with downloads',
          description: 'Identify access to suspicious categories followed by significant data transfer',
          query: 'dataset="$DATASET" url_category in ("newly-registered", "dynamic-dns") earliest=-24h\n| where bytes_received > 100000\n| summarize Downloads=count(), TotalBytes=sum(bytes_received) by source_user, url, destination_ip\n| order by TotalBytes desc'
