      falsePositives: ['New service deployments with legitimate new dependencies', 'CDN IP rotation causing baseline mismatches', 'Failover to backup services with different IPs'],
      tuningGuidance: 'Allow a learning period for new deployments before alerting. Exclude known CDN ranges that rotate frequently. Focus on connections to non-standard ports with significant data transfer.',
      investigationWorkflow: '1. Identify the container and unexpected destination\n2. Resolve the destination IP — is it a known service or suspicious?\n3. Check if a new dependency was recently deployed\n4. Review data transfer volume to the new destination\n5. Check if other containers from the same image show similar behavior\n6. If suspicious, block the destination and investigate the container',
      criblSearchQueries: [
        {
          name: 'Connections outside baseline',
          description: 'Find containers connecting to IP addresses not in their learned baseline',
          query: 'dataset="$DATASET" baseline_status="new" network_direction="outbound" earliest=-24h\n| summarize NewConnections=count(), Destinations=values(destination_ip), Ports=values(destination_port) by container_name, image_name, cluster\n| where NewConnections > 3\n| order by NewConnections desc'
        },
        {
          name: 'Data transfer to new destinations',
          description: 'Quantify data sent to previously unseen destinations for exfiltration assessment',
          query: 'dataset="$DATASET" baseline_status="new" network_direction="outbound" earliest=-24h\n| summarize TotalBytes=sum(bytes_sent), Connections=count() by container_name, destination_ip, destination_port, cluster\n| where TotalBytes > 1000000\n| order by TotalBytes desc'
        },
        {
          name: 'New destination trend by image',
          description: 'Track the rate of new destination connections per image over time',
          query: 'dataset="$DATASET" baseline_status="new" network_direction="outbound" earliest=-7d\n| timestats span=1d count() by image_name, cluster'
        }
      ]
