      id: 'sec-ise-004',
      name: 'Unauthorized VLAN Access',
      objective: 'Detect endpoints assigned to incorrect Security Group Tags (SGTs) or VLANs relative to their endpoint profile, indicating potential VLAN hopping, policy misconfiguration, or profile manipulation.',
      severity: 'Medium',
